var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"후아- 좋다아.","JPN":"ふわぁ……しみるうう……","ENG":"Huah! That was good.","TWN":"呼-真痛快。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"저어… 괜찮은 건가요? 벌써 세 병째 비우셨는데.","JPN":"あの……大丈夫ですか？　もう3本も飲み干していますけど。","ENG":"Uh... Are you all right? You've already downed three bottles.","TWN":"那個…你這樣喝沒問題嗎？已經喝三瓶咧？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"괜찮아. 괜찮아. 나처럼 오래 살다 보면 술이 달콤한 물처럼 느껴지거든.","JPN":"大丈夫、大丈夫。アタシみたいに長生きしていると、お酒がただの甘い水みたいに思えてくるのよ。","ENG":"I am fine. You live to be as old as I am, alcohol feels like sweet water.","TWN":"沒事啦～沒事。等你活到我這把歲數，就會把酒當水喝啦。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"哎呀！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그러고보니 제일 중요한 걸 안 물어봤네.","JPN":"そういえば、一番大事なことを聞くのを忘れていたわね。","ENG":"Come to think of it, I did not ask you the most important question.","TWN":"差點忘記問你最重要的事。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네…?","JPN":"はい……？","ENG":"Excuse me...?","TWN":"是什麼…？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"궁금했거든.","JPN":"気になっていたの。","ENG":"I am curious.","TWN":"我很好奇，"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"엘리시온의 아이가 어쩌다 동토를 넘어 여기까지 오게 된 건지.","JPN":"エリシオンの子が、どういう経緯で凍土を越えて、ここまで辿りついたのか。","ENG":"Why did an Elysion girl like yourself cross the gelid lands and arrive here?","TWN":"艾利森的人為何會越過凍土來到這裡？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"전… 그러니까…","JPN":"えっと……それは……","ENG":"Uh... Well...","TWN":"因為…我…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"요정을 찾고 있었어요.","JPN":"妖精を探していたんです。","ENG":"I'm looking for a fairy.","TWN":"在尋找精靈。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"꼭 빌고 싶은 소원이 있거든요.","JPN":"叶えてもらいたい願いがあって。","ENG":"There is a wish that I must make.","TWN":"我有必須要實現的願望。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"소원?","JPN":"願い？","ENG":"A wish?","TWN":"願望？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그런 일에 목숨까지 걸고 동토로 나오다니. 용기가 대단하네.","JPN":"そのために命がけで凍土までやって来るなんて、すごい勇気ね。","ENG":"I applaud your courage for venturing into the gelid lands and risking your life for something like that.","TWN":"然後你就賭上性命來到凍土嗎？勇氣可嘉呢。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"애써 포장해주시지 않아도 돼요. 비웃음을 살 일이라는 건 저도 아니까.","JPN":"そのように言っていただかなくてもいいんです。笑われるようなことをやっているのはわかっていますから。","ENG":"You don't have to sugarcoat it. I already know it was a stupid thing to do.","TWN":"你不需要說這種好聽話，我自己也知道這件事很可笑。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"왜 비웃을 거라고 생각하는데?","JPN":"どうして笑われると思うの？","ENG":"Why do you think so?","TWN":"哪裡可笑？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"그야…","JPN":"それは……","ENG":"Because...","TWN":"因為…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"이 시대에 요정을 실제로 본 사람은 한 명도 없으니까요.","JPN":"今の時代に、妖精を実際に見たことのある人間は、一人もいませんからね。","ENG":"there is nobody who has ever seen a fairy in this age.","TWN":"現在這個世代，根本沒有人親眼見過精靈。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"누가 듣더라도 터무니없는 얘기라고 생각하겠죠.","JPN":"誰に話しても、荒唐無稽な話だと思われるのは仕方ないと思います。","ENG":"Anyone hearing me will think that it's all nonsense.","TWN":"都是只聽某人說過，但是毫無根據。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"터무니없는 가능성을 좇는다는 건, 그만큼 절실하다는 뜻이기도 하지.","JPN":"根拠のない可能性を追っているということは、それだけ切実な願いということよね。","ENG":"Pursuing an absurd possibility just shows how desperate you are.","TWN":"會追求毫無根據的可能性，也就表示你有多急迫。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"난 그런 절실한 마음을 비웃음으로 짓밟는 짓은 하지 않아.","JPN":"アタシはそれほどの思いを、あざ笑ったりはしないわ。","ENG":"I have no intent to trample on your desperateness with ridicule.","TWN":"我不認為這樣的急迫有什麼可笑的。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"당신은 좋은 사람인 것 같네요.","JPN":"あなたはいい人なんですね。","ENG":"I think you're a good person.","TWN":"你是好人。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"후훗, 좋은 사람이라…","JPN":"ふふ、いい人ね……","ENG":"Fu fuu, a good person, you say...","TWN":"呵呵，好人嗎…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"그럼 내가 악마일 거라는 오해는 이제 풀린 거니?","JPN":"じゃあ、アタシが悪魔かもしれないという疑いは晴れたのかしら？","ENG":"Then, has your misunderstanding that I am a devil been resolved?","TWN":"所以你說我是魔鬼的事算是解開誤會囉？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"네?! 그걸 어떻게…?!","JPN":"はいっ！？　なんでそれを……！？","ENG":"What?! How did you–?!","TWN":"什麼？！你怎麼會…？！"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"아니, 저는 당신이 악마 그 자체라기보단 당신 능력이 악마 같다고 생각하긴 했는데요…!","JPN":"い、いや、私はあなたが悪魔というより、その能力が悪魔のようだと思っただけで……！","ENG":"No, I don't think you're a devil yourself. But I do think that your abilities are somewhat devil-like...!","TWN":"不是，我的意思不是你是魔鬼，而是你的能力像魔鬼…！"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_WANDER","text":{"KOREA":"앗… 말해버렸다.","JPN":"あっ……言っちゃった……","ENG":"Oops... I just said that out loud.","TWN":"哇…說溜嘴了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_WITH_OWL","text":{"KOREA":"이해해.","JPN":"そう思うのも無理ないわね。","ENG":"I understand.","TWN":"我明白。"},"stage":{"bg":"WOODHOUSE","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_WANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_WITH_OWL","face":"UNIT_PRIDE"}}}}]`);export{e as default};